const std = @import("std");

const Item = struct { value: u32 };

pub fn build(allocator: std.mem.Allocator, raw: []const u8) !std.json.ArrayHashMap(Item) {
    var items: std.json.ArrayHashMap(Item) = .{ .map = .empty };
    errdefer items.map.deinit(allocator);

    const key = try allocator.dupe(u8, raw);
    try items.map.put(allocator, key, .{ .value = 1 });
    return items;
}

pub fn release(allocator: std.mem.Allocator, items: *std.json.ArrayHashMap(Item)) void {
    items.map.deinit(allocator);
}

